import{_ as a,o as e,c as i,a2 as n}from"./chunks/framework.BWSdbvGU.js";const l="/CS-Note/assets/file-permissions-rwx.CguJIgPq.jpg",t="/CS-Note/assets/rwx-standard-unix-permission-bits.jmlALAXT.png",k=JSON.parse('{"title":"文件","description":"","frontmatter":{},"headers":[],"relativePath":"Linux.md","filePath":"Linux.md","lastUpdated":1780390825000}'),p={name:"Linux.md"};function r(d,s,o,h,c,u){return e(),i("div",null,[...s[0]||(s[0]=[n('<h1 id="文件" tabindex="-1">文件 <a class="header-anchor" href="#文件" aria-label="Permalink to &quot;文件&quot;">​</a></h1><h2 id="文件属性" tabindex="-1">文件属性 <a class="header-anchor" href="#文件属性" aria-label="Permalink to &quot;文件属性&quot;">​</a></h2><p>用户分为三种：文件拥有者、群组以及其它人，对不同的用户有不同的文件权限。</p><p>使用 <code>ls -l</code>查看一个文件时，会显示一个文件的信息，例如 <code>drwxr-xr-x 3 root root 17 May 6 00:14 .config</code>，对这个信息的解释如下：</p><ul><li><p>drwxr-xr-x：第 1 位为<strong>文件类型</strong>字段，后 9 位为<strong>文件权限</strong>字段 常见的文件类型及其含义有：</p><ul><li><code>d</code>：目录</li><li><code>-</code>：文件</li><li><code>l</code>：链接文件（link）</li></ul><p>文件权限：9 位的文件权限字段中，每 3 个为一组，共 3 组，9 位的文件权限字段中，每 3 个为一组，共 3 组。一组权限有以下选择：</p><ul><li><code>r</code>：读</li><li><code>w</code>：写</li><li><code>x</code>：执行</li><li><code>-</code>：没有该种权限</li></ul><p>其中rwx三种权限从左向右排列，如图所示：</p><p><img src="'+l+'" alt="img"></p></li><li><p>3：链接数</p></li><li><p>root：文件拥有者</p></li><li><p>root：所属群组</p></li><li><p>17：文件大小</p></li><li><p>May 6 00:14：文件最后被修改的时间 文件时间有以下三种：</p><ul><li>modification time (mtime)：文件的内容更新就会更新；</li><li>status time (ctime)：文件的状态（权限、属性）更新就会更新；</li><li>access time (atime)：读取文件时就会更新。</li></ul></li><li><p>.config：文件名</p></li></ul><h2 id="修改权限-chmod" tabindex="-1">修改权限 chmod <a class="header-anchor" href="#修改权限-chmod" aria-label="Permalink to &quot;修改权限 chmod&quot;">​</a></h2><p>可以将一组权限用数字来表示，此时一组权限的 3 个位当做二进制数字的位，从左到右每个位的权值为 4、2、1，即每个权限对应的数字权值为 r : 4、w : 2、x : 1。三者相加7就是改组权限的值。例如将 .bashrc 文件的权限修改为 <code>-rwxr-xr--</code>：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 754</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .bashrc</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><img src="'+t+`" alt="img"></p><h2 id="默认权限" tabindex="-1">默认权限 <a class="header-anchor" href="#默认权限" aria-label="Permalink to &quot;默认权限&quot;">​</a></h2><ul><li>文件默认权限：文件默认没有可执行权限，因此为 666，也就是 -rw-rw-rw- 。</li><li>目录默认权限：目录必须要能够进入，也就是必须拥有可执行权限，因此为 777 ，也就是 drwxrwxrwx。</li></ul><h2 id="目录的权限" tabindex="-1">目录的权限 <a class="header-anchor" href="#目录的权限" aria-label="Permalink to &quot;目录的权限&quot;">​</a></h2><p>文件名不是存储在一个文件的内容中，而是存储在一个文件所在的目录中。因此，拥有文件的 w 权限并不能对文件名进行修改。还需要有文件所在<strong>目录的w权限</strong>。</p><p>目录存储文件列表，一个目录的权限也就是对其文件列表的权限。因此，目录的 r 权限表示可以读取文件列表；w 权限表示可以修改文件列表，也就是添加删除文件，以及修改文件名；</p><blockquote><p>x 权限可以让该目录成为工作目录，x 权限是 r 和 w 权限的基础，如果不能使一个目录成为工作目录，也就没办法读取文件列表以及对文件列表进行修改了。</p><p>即：对目录而言，没有x权限就没有w和r权限。</p></blockquote><h2 id="设置所有者-chown" tabindex="-1">设置所有者 chown <a class="header-anchor" href="#设置所有者-chown" aria-label="Permalink to &quot;设置所有者 chown&quot;">​</a></h2><p>用于设置文件所有者和文件关联组。需要超级用户 <strong>root</strong> 的权限</p><p>Linux/Unix 是多人多工操作系统，所有的文件皆有拥有者。利用 chown 将指定文件的拥有者改为指定的用户或组，用户可以是用户名或者用户 ID，组可以是组名或者组 ID，文件是以空格分开的要改变权限的文件列表，支持通配符。</p><p>把 /var/run/httpd.pid 的所有者设置 root：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chown</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/run/httpd.pid</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>将文件 file1.txt 的拥有者设为 runoob，群体的使用者 runoobgroup :</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chown</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> runoob:runoobgroup</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> file1.txt</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h1 id="用户" tabindex="-1">用户 <a class="header-anchor" href="#用户" aria-label="Permalink to &quot;用户&quot;">​</a></h1><h2 id="创建用户账号-useradd" tabindex="-1">创建用户账号 useradd <a class="header-anchor" href="#创建用户账号-useradd" aria-label="Permalink to &quot;创建用户账号 useradd&quot;">​</a></h2><p>帐号建好之后，再用 passwd 设定帐号的密码</p><p>可用 userdel 删除帐号。</p><p>使用 useradd 指令所建立的帐号，实际上是保存在 /etc/passwd 文本文件中。</p><p>添加一般用户：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">useradd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tt</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>为添加的用户指定相应的用户组：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">useradd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tt</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>创建一个系统用户：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">useradd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tt</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>为新添加的用户指定home目录：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">useradd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/myd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tt</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="删除用户账号-userdel" tabindex="-1">删除用户账号 userdel <a class="header-anchor" href="#删除用户账号-userdel" aria-label="Permalink to &quot;删除用户账号 userdel&quot;">​</a></h2><p>userdel可删除用户帐号与相关的文件。若不加参数，则仅删除用户帐号，而不删除相关文件。</p><h1 id="挂载点" tabindex="-1">挂载点 <a class="header-anchor" href="#挂载点" aria-label="Permalink to &quot;挂载点&quot;">​</a></h1><h2 id="查看所有挂载点" tabindex="-1">查看所有挂载点 <a class="header-anchor" href="#查看所有挂载点" aria-label="Permalink to &quot;查看所有挂载点&quot;">​</a></h2><p>用<code>df -h</code>查看，最后一列就是挂载点，例如：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Filesystem                  Size  Used  Avail  Use%  Mounted on</span></span>
<span class="line"><span>/dev/mapper/unikylin-root   50G   48.5G  1.5G  97%  /</span></span>
<span class="line"><span>/dev/mapper/unikylin-home   2.2T  100G   2.1T   5%  /home</span></span>
<span class="line"><span>/dev/sda1                   976M  120M   780M  14%  /boot</span></span>
<span class="line"><span>tmpfs                       7.8G     0   7.8G   0%  /dev/shm</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>一个反直觉的现象是，挂载点<code>/home</code>的容量竟然比<code>/</code>还大。这是因为 <strong>Linux 中 “目录结构” 和 “存储分区” 是分离的</strong>——<code>/home</code>虽然在目录树里属于<code>/</code>（root 根目录）的子目录，但它被<strong>单独分区并挂载</strong>了，所以会占用独立的存储空间，并不从<code>/</code>的 50G 空间中分配。</p><p>而路径<code>/var/lib/docker</code>则属于根目录<code>/</code>，因为这个路径没有<strong>挂载点</strong>，就严格遵守linux的目录结构，它的空间也不可能大于根目录。</p><h2 id="查看一个路径的挂载点" tabindex="-1">查看一个路径的挂载点 <a class="header-anchor" href="#查看一个路径的挂载点" aria-label="Permalink to &quot;查看一个路径的挂载点&quot;">​</a></h2><p>可以用<code>df -h [路径]</code>查看：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># df -h /dev/mapper/unikylin-home/abc</span></span>
<span class="line"><span>/home</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h1 id="正则表达式" tabindex="-1">正则表达式 <a class="header-anchor" href="#正则表达式" aria-label="Permalink to &quot;正则表达式&quot;">​</a></h1><p>在文件 file.txt 中查找字符串 &quot;hello&quot;，并打印匹配的行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> file.txt</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>常用参数：</p><ul><li>-A 10：除了显示查找命中的行，再往后输出10行</li><li>-C 10：显示命中行前后的10行</li></ul>`,51)])])}const m=a(p,[["render",r]]);export{k as __pageData,m as default};
